import React, { useEffect, useState } from 'react';
import { Outlet, NavLink, useLocation } from 'react-router-dom';

const navItems = [
  { path: '/dashboard', label: 'Dashboard' },
  { path: '/profiles', label: 'Profils' },
  { path: '/templates', label: 'Templates' },
  { path: '/transformation', label: 'Transformation' },
  { path: '/offres', label: "Offres d'emploi" },
  { path: '/agenda', label: 'Agenda' },
];

export default function Layout() {
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    onScroll();
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const now = new Date();
  const greeting =
    now.getHours() < 12 ? 'Bonjour' : now.getHours() < 18 ? 'Bon après-midi' : 'Bonsoir';
  const dateStr = now.toLocaleDateString('fr-FR', {
    weekday: 'long', day: 'numeric', month: 'long',
  });

  const currentNav = navItems.find((n) => location.pathname.startsWith(n.path));
  const isDashboard = location.pathname === '/dashboard';

  return (
    <div style={{ minHeight: '100vh', backgroundColor: 'hsl(var(--background))' }}>
      {/* ── Floating Nav ── */}
      <div
        style={{
          position: 'sticky',
          top: 0,
          zIndex: 50,
          transition: 'all 0.5s ease',
          padding: scrolled ? '0' : '24px 24px 0',
        }}
      >
        <header
          style={{
            backgroundColor: 'hsl(var(--nav-bg))',
            color: 'hsl(var(--nav-foreground))',
            transition: 'all 0.5s ease',
            borderRadius: scrolled ? '0' : '1.5rem',
            boxShadow: scrolled ? 'var(--shadow-nav)' : 'var(--shadow-lg)',
            maxWidth: scrolled ? '100%' : '1400px',
            margin: scrolled ? '0' : '0 auto',
          }}
        >
          {/* Top row */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              padding: scrolled ? '12px 32px' : '20px 32px',
              transition: 'padding 0.5s ease',
            }}
          >
            {/* Brand + Nav */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '40px' }}>
              <NavLink to="/dashboard" style={{ display: 'flex', alignItems: 'center', gap: '10px', textDecoration: 'none' }}>
                <div
                  style={{
                    width: 36, height: 36, borderRadius: '12px',
                    background: 'linear-gradient(135deg, hsl(var(--primary)), hsl(var(--primary-glow)))',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                  }}
                >
                  <span className="font-serif" style={{ color: 'white', fontSize: '1.25rem', lineHeight: 1 }}>t</span>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', lineHeight: 1, gap: '2px' }}>
                  <span style={{ fontWeight: 600, fontSize: '0.9375rem', letterSpacing: '-0.01em', color: 'hsl(var(--nav-foreground))' }}>
                    Tritux RH
                  </span>
                  <span style={{ fontSize: '0.625rem', textTransform: 'uppercase', letterSpacing: '0.18em', color: 'hsl(var(--nav-muted))' }}>
                    Studio RH
                  </span>
                </div>
              </NavLink>

              <nav style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                {navItems.map((item) => (
                  <NavLink
                    key={item.path}
                    to={item.path}
                    className={({ isActive }) => `nav-link${isActive ? ' nav-link-active' : ''}`}
                  >
                    {item.label}
                  </NavLink>
                ))}
              </nav>
            </div>

            {/* Actions */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <NavLink
                to="/parametres"
                style={{
                  display: 'flex', alignItems: 'center', gap: '10px',
                  padding: '4px 8px 4px 4px', borderRadius: '9999px',
                  textDecoration: 'none',
                  transition: 'background 0.2s',
                }}
                onMouseEnter={e => e.currentTarget.style.background = 'hsl(var(--nav-active) / 0.6)'}
                onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
              >
                <div
                  style={{
                    width: 32, height: 32, borderRadius: '9999px',
                    background: 'linear-gradient(135deg, hsl(var(--primary)), hsl(var(--primary-glow)))',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    border: '1px solid hsl(var(--nav-active))',
                  }}
                >
                  <span style={{ color: 'white', fontSize: '0.75rem', fontWeight: 700 }}>RH</span>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', lineHeight: 1.2 }}>
                  <span style={{ fontSize: '0.75rem', fontWeight: 500, color: 'hsl(var(--nav-foreground))' }}>RH Tritux</span>
                  <span style={{ fontSize: '0.625rem', color: 'hsl(var(--nav-muted))' }}>Responsable RH</span>
                </div>
              </NavLink>
            </div>
          </div>

          {/* Greeting row */}
          <div
            style={{
              overflow: 'hidden',
              maxHeight: scrolled ? '0' : '160px',
              opacity: scrolled ? 0 : 1,
              transition: 'max-height 0.5s ease, opacity 0.5s ease',
            }}
          >
            <div
              style={{
                padding: '20px 32px 28px',
                display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between',
                borderTop: '1px solid hsl(var(--nav-active) / 0.4)',
                gap: '24px',
              }}
            >
              <div>
                <p style={{ fontSize: '0.6875rem', textTransform: 'uppercase', letterSpacing: '0.2em', color: 'hsl(var(--nav-muted))', marginBottom: '8px', margin: '0 0 8px' }}>
                  {currentNav?.label || 'Espace personnel'}
                </p>

              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: 'hsl(var(--nav-muted))', fontSize: '0.875rem', whiteSpace: 'nowrap' }}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
                </svg>
                <span style={{ textTransform: 'capitalize' }}>{dateStr}</span>
              </div>
            </div>
          </div>
        </header>
      </div>

      {/* Main */}
      <main
        style={{
          padding: '32px 24px',
          maxWidth: '1400px',
          margin: '0 auto',
          animation: 'fade-in 0.4s ease-out',
        }}
      >
        <Outlet />
      </main>
    </div>
  );
}
